// Test that cluster updates correctly replace old cluster info in the info map.
TEST_F(UdpProxyFilterTest, ClusterDynamicInfoMapUpdate) {
  InSequence s;

  setup(readConfig(R"EOF(
stat_prefix: foo
matcher:
  on_no_match:
    action:
      name: route
      typed_config:
        '@type': type.googleapis.com/envoy.extensions.filters.udp.udp_proxy.v3.Route
        cluster: fake_cluster
  )EOF"));

  // Create a session with the initial cluster.
  expectSessionCreate(upstream_address_);
  test_sessions_[0].expectWriteToUpstream("hello", 0, nullptr, true);
  recvDataFromDownstream("10.0.0.1:1000", "10.0.0.2:80", "hello");
  EXPECT_EQ(1, config_->stats().downstream_sess_total_.value());
  EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());

  // Now simulate a cluster update with a new ThreadLocalCluster.
  // Create a new mock cluster with the same name.
  NiceMock<Upstream::MockThreadLocalCluster> updated_cluster;
  updated_cluster.cluster_.info_->name_ = "fake_cluster";

  {
    Upstream::ThreadLocalClusterCommand command =
        [&updated_cluster]() -> Upstream::ThreadLocalCluster& {
      return updated_cluster;
    };
    cluster_update_callbacks_->onClusterAddOrUpdate("fake_cluster", command);
  }

  // With the fix, the cluster info map should now point to the new cluster.
  // Verify this by creating a session with the updated cluster.
  // This session should use the updated cluster, not the old one.
  auto updated_host = createHost(Network::Utility::parseInternetAddressAndPort("10.0.0.3:443", false));
  EXPECT_CALL(updated_cluster.lb_, chooseHost(_))
      .WillOnce(Return(updated_host));

  Network::MockSocket* updated_socket = new NiceMock<Network::MockSocket>();
  EXPECT_CALL(dynamic_cast<TestUdpProxyFilter&>(*filter_), createUdpSocket(_))
      .WillOnce(ReturnNew<Network::MockSocket>());

  test_sessions_[1].expectWriteToUpstream("world", 0, nullptr, true);
  recvDataFromDownstream("10.0.0.1:1001", "10.0.0.2:80", "world");
}

